CREATE TABLE host_samples_10s (ts INTEGER NOT NULL, host_id TEXT NOT NULL, boot_session_id TEXT, cpu_busy_pct REAL, load_1 REAL, memory_used_bytes INTEGER, network_rx_bps REAL, network_tx_bps REAL, PRIMARY KEY(host_id,ts));
CREATE TABLE resource_samples_10s (ts INTEGER NOT NULL, resource_id TEXT NOT NULL, cpu_host_pct REAL, memory_working_set_bytes INTEGER, network_rx_bps REAL, network_tx_bps REAL, active_instance_count INTEGER NOT NULL, PRIMARY KEY(resource_id,ts));
CREATE TABLE container_instance_samples_10s (ts INTEGER NOT NULL, container_instance_id TEXT NOT NULL, cpu_host_pct REAL, memory_working_set_bytes INTEGER, PRIMARY KEY(container_instance_id,ts));
CREATE TABLE events (id TEXT PRIMARY KEY, ts INTEGER NOT NULL, host_id TEXT, resource_id TEXT, container_instance_id TEXT, type TEXT NOT NULL, severity TEXT NOT NULL, summary TEXT NOT NULL, details_json TEXT, correlation_key TEXT, source TEXT NOT NULL, created_at INTEGER NOT NULL);
CREATE INDEX events_ts ON events(ts DESC); CREATE INDEX events_resource_ts ON events(resource_id,ts DESC);
CREATE TABLE collector_state_events (id TEXT PRIMARY KEY, ts INTEGER NOT NULL, collector_name TEXT NOT NULL, previous_state TEXT, new_state TEXT NOT NULL, reason_code TEXT, message TEXT);
CREATE TABLE settings (key TEXT PRIMARY KEY,value_json TEXT NOT NULL,updated_at INTEGER NOT NULL,updated_by TEXT); CREATE TABLE encrypted_secrets (key TEXT PRIMARY KEY,ciphertext BLOB NOT NULL,nonce BLOB NOT NULL,algorithm TEXT NOT NULL,key_version INTEGER NOT NULL,updated_at INTEGER NOT NULL); CREATE TABLE users (id TEXT PRIMARY KEY,username TEXT UNIQUE NOT NULL,password_hash TEXT NOT NULL,created_at INTEGER NOT NULL,updated_at INTEGER NOT NULL); CREATE TABLE sessions (id_hash TEXT PRIMARY KEY,user_id TEXT NOT NULL,created_at INTEGER NOT NULL,last_seen_at INTEGER NOT NULL,expires_at INTEGER NOT NULL,absolute_expires_at INTEGER NOT NULL,revoked_at INTEGER);
